import json
import boto3
import requests
from urllib.parse import urlparse

s3 = boto3.client('s3')

def lambda_handler(event, context):
    # Get the URL from the X-Enrich-URL header
    url = event['headers']['X-Enrich-URL']
    
    # Parse the URL to get the bucket and key
    parsed_url = urlparse(url)
    bucket = parsed_url.netloc
    key = parsed_url.path[1:]
    
    # Fetch the data from S3 using the requests library
    response = s3.get_object(Bucket=bucket, Key=key)
    data = json.loads(response['Body'].read())
    
    # Add the data to the event object
    event['data'] = data
    
    # Forward the event to the origin
    return event